5	const fs = require('fs');
6	const path = require('path');
7	
8	const OBSIDIAN_DIR = 'E:/道友的宝贝/道友的宝贝/对话归档/CC';
9	const REGISTRY_FILE = 'D:/ClaudeWorkspace/.session_registry.json';
10	const SESSION_NOTE = 'D:/ClaudeWorkspace/当前会话笔记.md';
11	
12	if (!fs.existsSync(OBSIDIAN_DIR)) {
13	  fs.mkdirSync(OBSIDIAN_DIR, { recursive: true });
14	}
15	
16	// Read session registry
17	let registry = {};
18	if (fs.existsSync(REGISTRY_FILE)) {
19	  try { registry = JSON.parse(fs.readFileSync(REGISTRY_FILE, 'utf-8')); } catch (e) {}
20	}
21	
22	// Only archive if this session is registered in Obsidian
23	const isRegistered = registry.obsidianNotePath && fs.existsSync(registry.obsidianNotePath);
24	
25	if (isRegistered && fs.existsSync(SESSION_NOTE)) {
26	  const content = fs.readFileSync(SESSION_NOTE, 'utf-8');
27	  if (content.trim().length > 0) {
28	    fs.copyFileSync(SESSION_NOTE, registry.obsidianNotePath);
29	    console.log(`[backup-session] ✅ 已同步到 ${path.basename(registry.obsidianNotePath)}`);
30	  }
31	} else {
32	  console.log('[backup-session] ⏭ 无已注册的 Obsidian 笔记，跳过归档');
33	}
