35	// Clean registry at session end (remove session ID, keep note reference)
36	if (fs.existsSync(REGISTRY_FILE)) {
37	  try {
38	    const reg = JSON.parse(fs.readFileSync(REGISTRY_FILE, 'utf-8'));
39	    reg.activeSessionId = '';
40	    reg.lastSyncTime = new Date().toISOString();
41	    fs.writeFileSync(REGISTRY_FILE, JSON.stringify(reg, null, 2));
42	  } catch (e) {}
43	}
